const express = require('express');
const multer  = require('multer');
const fs = require('fs');
const { XMLParser } = require('fast-xml-parser');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload', upload.single('file'), (req, res) => {
    if (!req.file) {
        return res.status(400).send('No file uploaded.');
    }

    const xmlFilePath = req.file.path;
    const options = {
        attributeNamePrefix: "",
        attrNodeName: "attr",
        textNodeName: "#text",
        ignoreAttributes: false,
        cdataPositionChar: "&",
        format: true,
        indentBy: "  ",
        supressEmptyNode: false,
        tagValueProcessor: a => a,
        allowBooleanAttributes: false,
        parseNodeValue: true,
        parseAttributeValue: false,
        trimValues: true,
        cdataPropName: "#cdata",
        childrenAsArray: true
    };

    const parser = new XMLParser(options);
    let xmlData;
    try {
        const xmlContent = fs.readFileSync(xmlFilePath, 'utf8');
        xmlData = parser.parse(xmlContent);
    } catch (e) {
        return res.status(500).send('Failed to parse XML file.');
    }

    // Process the parsed XML data into a configuration object
    const configObject = processXmlData(xmlData);

    fs.unlinkSync(xmlFilePath); // Clean up: remove the uploaded file

    res.json(configObject);
});

function processXmlData(xmlData) {
    // Implement your logic to extract configuration settings from the XML data
    // Example:
    const configObject = {};
    if (xmlData.configuration && xmlData.configuration.settings) {
        xmlData.configuration.settings.forEach(setting => {
            configObject[setting.name] = setting.value;
        });
    }
    return configObject;
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});